+    const vb: [*]const @Vector(VEC_F64_LEN, f64) = @alignCast(@ptrCast(b.ptr));
+    for (0..chunks) |i| {
+        d[i] = va[i] * vb[i];
+    }
+
+    for (0..remainder) |i| {
+        const idx = chunks * VEC_F64_LEN + i;
